var sensorStatus = msg.temperatureWater_status;
var temperature = msg.temperatureWater;
var alarmType = "Temperatura da agua";

function calcularDiferencaTempoEmMinutos(data) {
    if (!data || data.length < 2) {
        return 0;
    }
    var primeiraData = data[0].ts;
    var ultimaData = data[data.length - 1].ts;
    return (ultimaData - primeiraData) / (1000 * 60);
}

function todosMaiorOuIgual(data, limite) {
    return data && data.length > 0 && data.every(function(item) {
        return Number(item.value) >= limite;
    });
}

function todosMenorOuIgual(data, limite) {
    return data && data.length > 0 && data.every(function(item) {
        return Number(item.value) <= limite;
    });
}

function todosDiferentes(data, valor) {
    return data && data.length > 0 && data.every(function(item) {
        return item.value !== valor;
    });
}

var temperatureDelta = JSON.parse(metadata.temperatureWater || "[]");
var statusDelta = JSON.parse(metadata.temperatureWater_status || "[]");

var diferencaTemperaturaMin = calcularDiferencaTempoEmMinutos(temperatureDelta);
var diferencaStatusMin = calcularDiferencaTempoEmMinutos(statusDelta);

var historicoTemperaturaAlta = todosMaiorOuIgual(temperatureDelta, 50);
var historicoTemperaturaBaixa = todosMenorOuIgual(temperatureDelta, 20);
var historicoStatusEmAlerta = todosDiferentes(statusDelta, "OK");

if (temperatureDelta.length > 20) {
    if (temperature > 50 && historicoTemperaturaAlta) {
        msg.status = {
            errorStatus: "ALERTA",
            message: "A temperatura da agua esta ALTA ha " + diferencaTemperaturaMin + " minutos. Valor atual: " + temperature + " C",
            alarmType: alarmType
        };
    }

    if (temperature < 20 && historicoTemperaturaBaixa) {
        msg.status = {
            errorStatus: "ALERTA",
            message: "A temperatura da agua esta BAIXA ha " + diferencaTemperaturaMin + " minutos. Valor atual: " + temperature + " C",
            alarmType: alarmType
        };
    }

    if (sensorStatus !== "OK" && historicoStatusEmAlerta) {
        msg.status = {
            errorStatus: "ALERTA",
            message: "Sensor de temperatura da agua em alerta ha " + diferencaStatusMin + " minutos",
            alarmType: alarmType
        };
    }
}

return { msg: msg, metadata: metadata, msgType: msgType };

