    if (!data || data.length < 2) {
        return 0;
    }
    var primeiraData = data[0].ts;
    var ultimaData = data[data.length - 1].ts;
    return (ultimaData - primeiraData) / (1000 * 60);
}

function todosSaoOpen(data) {
    return data && data.length > 0 && data.every(function(item) {
        return item.value === "OPEN";
    });
}

function todosDiferentes(data, valor) {
    return data && data.length > 0 && data.every(function(item) {
        return item.value !== valor;
    });
}

var doorHistory = JSON.parse(metadata.doorSensor || "[]");
var statusHistory = JSON.parse(metadata.doorSensor_status || "[]");

var diferencaDoorMin = calcularDiferencaTempoEmMinutos(doorHistory);
var diferencaStatusMin = calcularDiferencaTempoEmMinutos(statusHistory);

var historicoPortaAberta = todosSaoOpen(doorHistory);
var historicoStatusEmAlerta = todosDiferentes(statusHistory, "OK");

if (doorHistory.length > 35) {
    if (isolatedStatus !== "OK" && historicoStatusEmAlerta) {
        msg.status = {
            errorStatus: status,
            message: "Sensor de porta em alerta ha " + diferencaStatusMin + " minutos",
            alarmType: alarmType
        };
        msg.sensorproblem = true;
    } else if (stateDoor !== "CLOSED" && historicoPortaAberta) {
        msg.status = {
            errorStatus: status,
            message: "A porta do equipamento esta em ALERTA: " + stateDoor + " ha " + diferencaDoorMin + " minutos",
            alarmType: alarmType
        };
        msg.sensorproblem = false;
    }
}

return { msg: msg, metadata: metadata, msgType: msgType };

