function pesoAumentandoUltimo(data) {
    if (!data || data.length < 3) {
        return false;
    }

    var deviceName = metadata.deviceName || "";
    var modelDevice = parseInt(deviceName.substring(0, 3), 10);

    if (isNaN(modelDevice)) {
        return false;
    }

    var porcentagem = 2;
    var tolerancia = (porcentagem / 100) * modelDevice;

    var primeiro = Math.ceil(Number(data[0].value) + tolerancia);
    var meioIndex = Math.floor(data.length / 2);
    var meio = Math.ceil(Number(data[meioIndex].value));
